/** بناء HTML الكليشة (ترويسة المدرسة) — مطابق للأصلي: 3 أعمدة مع شعارات Base64 */
export function buildLetterheadHtml(settings: {
  letterheadMode: string;
  letterheadImageUrl?: string;
  schoolName?: string;
  eduAdmin?: string;
  eduDept?: string;
  letterhead?: string;
}): string {
  if (settings.letterheadMode === 'image' || settings.letterheadMode === 'Image') {
    const url = settings.letterheadImageUrl || '';
    if (url) {
      return `<div style="text-align:center;border-bottom:2px solid #000;padding-bottom:8px;margin-bottom:15px"><img src="${escapeHtml(url)}" style="height:80px;max-width:100%;object-fit:contain" alt="الشعار"></div>`;
    }
  }
  // وضع النص: كليشة بثلاثة أعمدة (شعار المملكة | بيانات المدرسة | شعار الوزارة)
  let schoolText = '';
  if (settings.letterhead && settings.letterhead.trim()) {
    schoolText = settings.letterhead;
  } else {
    const parts: string[] = [];
    if (settings.eduAdmin) parts.push(settings.eduAdmin);
    if (settings.eduDept) parts.push(settings.eduDept);
    if (settings.schoolName) parts.push(settings.schoolName);
    schoolText = parts.join('\n');
  }
  const lines = schoolText.split('\n').filter((l: string) => l.trim());
  let centerHtml = '<p style="font-size:13pt;font-weight:bold;margin:2px 0">المملكة العربية السعودية</p>'
    + '<p style="font-size:13pt;font-weight:bold;margin:2px 0">وزارة التعليم</p>';
  for (const line of lines) {
    centerHtml += `<p style="font-size:12pt;margin:2px 0">${escapeHtml(line.trim())}</p>`;
  }
  return `<table class="letterhead-table"><tr>`
    + `<td class="lh-logo"><img src="${LETTERHEAD_KSA_LOGO}" alt="شعار المملكة"></td>`
    + `<td class="lh-center">${centerHtml}</td>`
    + `<td class="lh-logo"><img src="${LETTERHEAD_MOE_LOGO}" alt="شعار الوزارة"></td>`
    + `</tr></table>`;
}

